import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.D36jym0Z.js";const u=JSON.parse('{"title":"Visual Inspector","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/visual-inspector.md","filePath":"user-guide/visual-inspector.md","lastUpdated":1784629191000}'),n={name:"user-guide/visual-inspector.md"};function o(l,e,r,h,d,c){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="visual-inspector" tabindex="-1">Visual Inspector <a class="header-anchor" href="#visual-inspector" aria-label="Permalink to &quot;Visual Inspector&quot;">​</a></h1><p>The visual inspector is a <strong>browser-based dashboard</strong> that shows TokenPilot&#39;s real-time behavior — cache efficiency, context trimming, and eviction decisions.</p><h2 id="opening-the-inspector" tabindex="-1">Opening the Inspector <a class="header-anchor" href="#opening-the-inspector" aria-label="Permalink to &quot;Opening the Inspector&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual</span></span></code></pre></div><p>This starts a local web server and opens your default browser.</p><p>You can also open it per-host:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual</span></span></code></pre></div><p>Or inside OpenClaw:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/lightmem2 visual</span></span></code></pre></div><h2 id="views" tabindex="-1">Views <a class="header-anchor" href="#views" aria-label="Permalink to &quot;Views&quot;">​</a></h2><h3 id="stabilizer-view" tabindex="-1">Stabilizer View <a class="header-anchor" href="#stabilizer-view" aria-label="Permalink to &quot;Stabilizer View&quot;">​</a></h3><p>Shows how the stable prefix is performing:</p><ul><li><strong>Stable vs. dynamic ratio</strong>: What portion of the context is cache-stable vs. turn-varying</li><li><strong>Cache hit rate</strong>: Percentage of input tokens served from cache each turn</li><li><strong>Per-turn stability</strong>: A timeline showing stability metrics turn by turn</li></ul><p>A high stable ratio and high cache hit rate mean the stabilizer is working well.</p><h3 id="reduction-view" tabindex="-1">Reduction View <a class="header-anchor" href="#reduction-view" aria-label="Permalink to &quot;Reduction View&quot;">​</a></h3><p>Shows what TokenPilot trimmed from tool output:</p><ul><li><strong>Per-turn reduction stats</strong>: How many bytes/tokens were trimmed each turn</li><li><strong>Before/after comparison</strong>: Tool output size before and after reduction</li><li><strong>Active passes</strong>: Which reduction passes are enabled and what they&#39;re doing</li></ul><p>Use this view when you want to check if reduction is being too aggressive or too conservative.</p><h3 id="eviction-view" tabindex="-1">Eviction View <a class="header-anchor" href="#eviction-view" aria-label="Permalink to &quot;Eviction View&quot;">​</a></h3><p>Shows lifecycle-aware pruning:</p><ul><li><strong>Session depth</strong>: Current turn count and total token count</li><li><strong>Eviction threshold</strong>: The configured limit before eviction starts</li><li><strong>Evicted turns</strong>: How many turns have been pruned</li><li><strong>Timeline</strong>: When eviction happened and what was removed</li></ul><p>Use this view when debugging why certain context seems to be missing.</p><h2 id="navigating" tabindex="-1">Navigating <a class="header-anchor" href="#navigating" aria-label="Permalink to &quot;Navigating&quot;">​</a></h2><ul><li><strong>Tabs</strong> at the top switch between Stabilizer, Reduction, and Eviction views</li><li><strong>Host dropdown</strong> changes which host&#39;s data you&#39;re viewing</li><li><strong>Session selector</strong> lets you view specific sessions</li><li>Data <strong>auto-updates</strong> as new turns complete</li></ul><h2 id="when-to-use-the-inspector" tabindex="-1">When to Use the Inspector <a class="header-anchor" href="#when-to-use-the-inspector" aria-label="Permalink to &quot;When to Use the Inspector&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Situation</th><th style="text-align:left;">View to check</th></tr></thead><tbody><tr><td style="text-align:left;">Cache savings seem lower than expected</td><td style="text-align:left;">Stabilizer</td></tr><tr><td style="text-align:left;">Model seems to miss important tool output</td><td style="text-align:left;">Reduction</td></tr><tr><td style="text-align:left;">Older context is disappearing too soon</td><td style="text-align:left;">Eviction</td></tr><tr><td style="text-align:left;">General health check</td><td style="text-align:left;">All three</td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>If the inspector doesn&#39;t open:</p><ol><li>Make sure TokenPilot has run at least one session</li><li>Check that the local server port isn&#39;t blocked</li><li>Try a different browser</li><li>Run <code>lightmem2 doctor</code> to verify TokenPilot is healthy</li></ol><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/plugin-catalog/tokenpilot/reports-and-visuals">Reports and Visuals</a> — understanding the metrics</li><li><a href="/LightMem2/user-guide/logs-and-diagnostics">Logs and Diagnostics</a> — text-based diagnostics</li></ul>`,31)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
